import React, { useState } from 'react';
import i1 from '../assets/images/i1.jpg';
import i2 from '../assets/images/i2.jpg';
import i3 from '../assets/images/i3.jpg';
import './NewArrivals.css';

const products = [
  { id: 1, img: i1, name: 'Shiny Dress',  brand: 'Al Karam', reviews: '4.1k', price: '95.50', stars: 5 },
  { id: 2, img: i2, name: 'Long Dress',   brand: 'Al Karam', reviews: '4.1k', price: '95.50', stars: 5 },
  { id: 3, img: i3, name: 'Full Sweater', brand: 'Al Karam', reviews: '4.1k', price: '95.50', stars: 5 },
  { id: 4, img: i1, name: 'Shiny Dress',  brand: 'Al Karam', reviews: '4.1k', price: '95.50', stars: 5 },
  { id: 5, img: i2, name: 'Long Dress',   brand: 'Al Karam', reviews: '4.1k', price: '95.50', stars: 5 },
  { id: 6, img: i3, name: 'Full Sweater', brand: 'Al Karam', reviews: '4.1k', price: '95.50', stars: 5 },
];

function Stars({ count }) {
  return (
    <span className="na-stars">
      {Array.from({ length: 5 }).map((_, i) => (
        <span key={i} className={i < count ? 'star filled' : 'star'}>★</span>
      ))}
    </span>
  );
}

export default function NewArrivals() {
  const [hovered, setHovered] = useState(null);

  return (
    <section className="na-section">
      {/* Header */}
      <div className="na-header">
        <h2 className="na-heading">New Arrivals</h2>
        <p className="na-sub">
          New Arrivals" means recently added or newly available items, usually in a
          store, website, or collection.
        </p>
      </div>

      {/* Product Grid */}
      <div className="na-grid">
        {products.map((p) => (
          <div
            key={p.id}
            className="na-card"
            onMouseEnter={() => setHovered(p.id)}
            onMouseLeave={() => setHovered(null)}
          >
            {/* Image */}
            <div className="na-img-wrap">
              <img src={p.img} alt={p.name} className="na-img" />
              {hovered === p.id && (
                <button className="na-add-btn">ADD TO CART</button>
              )}
            </div>

            {/* Info */}
            <div className="na-info">
              <div className="na-name-row">
                <span className="na-name">{p.name}</span>
                <Stars count={p.stars} />
              </div>
              <span className="na-brand">{p.brand}</span>
              <span className="na-reviews">({p.reviews}) Customer Reviews</span>
              <div className="na-price-row">
                <span className="na-price">${p.price}</span>
                <span className="na-sold">Almost Sold Out</span>
              </div>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
}
